rol		= NULL;UInt32			gRefNum				= 0;ControlRef		gMagicControl		= NULL;Boolean			gIsBattle			= false;short			gCurrMagic			= 0;Boolean			gMagicIsHeal		= false;Boolean			gMagicIsAll			= false;FSSpec			gSaveSpec			= {0, 0, "\p"};short			gShopSellPerc;short			gShopBuyPerc;short			gShopNumOfItems;ItemRef			gShopItems[kNumOfShopItems];BrowserRef		gShopItemsInfo[kNumOfShopItems];long			gShopItemPrice[kNumOfShopItems];Boolean			gShopItemIsSpecial[kNumOfShopItems];Boolean			gShopIsFree;Str255			gTempName;short			gTempMapSprt;short			gTempBattleSprt;Point			gTempHoldPos;Str255			gTempElement;Str255			gTempOccupation;Stats			gTempStats;//*************************************************************************************//  internal function declerations//*************************************************************************************pascal OSStatus		NewGameWindowHandler		(EventHandlerCallRef	myHandler,												EventRef				event,												void *					userData);pascal OSStatus		EquipmentWindowHandler		(EventHandlerCallRef	myHandler,												EventRef				event,												void *					userData);pascal OSStatus		InfoWindowHandler			(EventHandlerCallRef	myHandler,												EventRef				event,												void *					userData);pascal OSStatus		MagicWindowHandler			(EventHandlerCallRef	myHandler,												EventRef				event,												void *					userData);pascal OSStatus		TechWindowHandler			(EventHandlerCallRef	myHandler,												EventRef				event,												void *					userData);pascal OSStatus		ShopWindowHandler			(EventHandlerCallRef	myHandler,												EventRef				event,												void *					userData);pascal OSStatus		EquipmentKeyEventHandler	(EventHandlerCallRef	myHandler,												EventRef				event,												void *					userData);pascal OSStatus		MagicKeyEventHandler		(EventHandlerCallRef	myHandler,												EventRef				event,												void *					userData);pascal OSStatus		TechKeyEventHandler			(EventHandlerCallRef	myHandler,												EventRef				event,												void *					userData);pascal OSStatus		ShopKeyEventHandler			(EventHandlerCallRef	myHandler,												EventRef				event,												void *					userData);//*************************************************************************************//  Character functions//*************************************************************************************Boolean InstallCharacter (void){	IBNibRef nibRef;	error = CreateNibReference(CFSTR("DACharacter"), &nibRef);	error = CreateWindowFromNib(nibRef, CFSTR("NewGame1"), &gNewGame1);	ErrorCheck(error, "\pDACharacter:InstallCharacter:CreateWindowFromNib");	error = CreateWindowFromNib(nibRef, CFSTR("NewGame2"), &gNewGame2);	ErrorCheck(error, "\pDACharacter:InstallCharacter:CreateWindowFromNib");	error = CreateWindowFromNib(nibRef, CFSTR("NewGame3"), &gNewGame3);	ErrorCheck(error, "\pDACharacter:InstallCharacter:CreateWindowFromNib");	error = CreateWindowFromNib(nibRef, CFSTR("NewGame4"), &gNewGame4);	ErrorCheck(error, "\pDACharacter:InstallCharacter:CreateWindowFromNib");	error = CreateWindowFromNib(nibRef, CFSTR("NewGame5"), &gNewGame5);	ErrorCheck(error, "\pDACharacter:InstallCharacter:CreateWindowFromNib");	DisposeNibReference(nibRef);		EventTypeSpec mainSpec = {kEventClassCommand, kEventCommandProcess};	InstallWindowEventHandler(gNewGame1, NewEventHandlerUPP(NewGameWindowHandler), 1, &mainSpec, NULL, NULL);	InstallWindowEventHandler(gNewGame2, NewEventHandlerUPP(NewGameWindowHandler), 1, &mainSpec, NULL, NULL);	InstallWindowEventHandler(gNewGame3, NewEventHandlerUPP(NewGameWindowHandler), 1, &mainSpec, NULL, NULL);	InstallWindowEventHandler(gNewGame4, NewEventHandlerUPP(NewGameWindowHandler), 1, &mainSpec, NULL, NULL);	InstallWindowEventHandler(gNewGame5, NewEventHandlerUPP(NewGameWindowHandler), 1, &mainSpec, NULL, NULL);	SetControlFocus(gNewGame1, kDAApplicationSignature, 128);	ShowWindow(gNewGame1);	error = RunAppModalLoopForWindow(gNewGame1);	ErrorCheck(error, "\pDACharacter:InstallCharacter:RunAppModalLoopForWindow");	DisposeWindow(gNewGame1);	DisposeWindow(gNewGame2);	DisposeWindow(gNewGame3);	DisposeWindow(gNewGame4);	DisposeWindow(gNewGame5);		if(gReturnValue == false)		return false;		// -- Dispose Character Info --	error = DisposeSprite(gCharacterInfo.mapSprite);	ErrorCheck(error, "\pDACharacter:InstallCharacter:DisposeSprite");	error = DisposeSprite(gCharacterInfo.battleSprite);	ErrorCheck(error, "\pDACharacter:InstallCharacter:DisposeSprite");		pstrcpy(gCharacter.name, gTempName);	gCharacter.mapSpriteID = gTempMapSprt;	gCharacter.battleSpriteID = gTempBattleSprt;	gCharacter.holdPos = gTempHoldPos;	pstrcpy(gCharacter.heritage, gTempElement);	pstrcpy(gCharacter.occupation, gTempOccupation);	gCharacter.baseStats = gTempStats;		// -- Get and Set Character --	gCharacter.plugID	= 0;	gCharacter.mapID	= 0;	gCharacter.battleMenuPos.h = 329;	gCharacter.battleMenuPos.v = 223;	gCharacter.lv		= 1;	gCharacter.gold		= kStartingGold;		// -- Xyster --	if(pstrcmp(gCharacter.name, "\pXyster") == 0)	{		gCharacter.lv = kMaxLevel;		gCharacter.gold = kMaxGold;		gCharacter.baseStats.str = 10;		gCharacter.baseStats.def = 10;		gCharacter.baseStats.spd = 10;		gCharacter.baseStats.mag = 10;		gCharacter.baseStats.p = kMaxMainResist;		gCharacter.baseStats.m = kMaxMainResist;		gCharacter.baseStats.l = kMaxResistance;		gCharacter.baseStats.d = kMaxResistance;		gCharacter.baseStats.f = kMaxResistance;		gCharacter.baseStats.w = kMaxResistance;		gCharacter.baseStats.e = kMaxResistance;		gCharacter.baseStats.a = kMaxResistance;	}		// -- Get and Set Character 2 --	CalcCharacter();	gCharacter.currHP	= gCharacter.maxHP;	gCharacter.isWeapon		= false;	gCharacter.isSummon		= false;	gCharacter.numOfArmors	= 0;	gCharacter.numOfItems	= 0;	gCharacter.numOfMagics	= 0;	gCharacter.numOfTechs	= 0;	for(short i = 0; i < kMaxFlags; i++)		gCharacter.flag[i] = false;		// -- Get and Set Character Info --	PicHandle picture;	error = GetPicture(gCharacter.mapSpriteID, &picture);	ErrorCheck(error, "\pDACharacter:InstallCharacter:GetPicture");	error = GetSprite(picture, &gCharacterInfo.mapSprite);	ErrorCheck(error, "\pDACharacter:InstallCharacter:GetSprite");	gCharacterInfo.mapFacing = kMapFacingSouth1;	gCharacter.mapPosition.h = 0;	gCharacter.mapPosition.v = 0;	error = GetPicture(gCharacter.battleSpriteID, &picture);	ErrorCheck(error, "\pDACharacter:InstallCharacter:GetPicture");	error = GetSprite(picture, &gCharacterInfo.battleSprite);	ErrorCheck(error, "\pDACharacter:InstallCharacter:GetSprite");		// -- Starting Items --	gCharacter.weapon.itemType		= 1;	gCharacter.weapon.plugID		= 1;	gCharacter.weapon.resID			= 128;	gCharacter.isWeapon				= true;	gCharacter.armors[0].itemType	= 4;	gCharacter.armors[0].plugID		= 1;	gCharacter.armors[0].resID		= 128;	gCharacter.numOfArmors++;	gCharacter.armors[1].itemType	= 100;	gCharacter.armors[1].plugID		= 1;	gCharacter.armors[1].resID		= 129;	gCharacter.numOfArmors++;	if(pstrcmp(gCharacter.occupation, kOccupationSoldier) == 0)	{		gCharacter.armors[2].itemType	= kItemLv1;		gCharacter.armors[2].plugID		= 1;		gCharacter.armors[2].resID		= 500;		gCharacter.numOfArmors++;	}	else if(pstrcmp(gCharacter.occupation, kOccupationFigher) == 0)	{		gCharacter.armors[2].itemType	= kItemLv1;		gCharacter.armors[2].plugID		= 1;		gCharacter.armors[2].resID		= 501;		gCharacter.numOfArmors++;	}	else if(pstrcmp(gCharacter.occupation, kOccupationKnight) == 0)	{		gCharacter.armors[2].itemType	= kItemLv1;		gCharacter.armors[2].plugID		= 1;		gCharacter.armors[2].resID		= 502;		gCharacter.numOfArmors++;	}	else if(pstrcmp(gCharacter.occupation, kOccupationThief) == 0)	{		gCharacter.armors[2].itemType	= kItemLv1;		gCharacter.armors[2].plugID		= 1;		gCharacter.armors[2].resID		= 503;		gCharacter.numOfArmors++;	}	else if(pstrcmp(gCharacter.occupation, kOccupationMage) == 0)	{		gCharacter.armors[2].itemType	= kItemLv1;		gCharacter.armors[2].plugID		= 1;		gCharacter.armors[2].resID		= 504;		gCharacter.numOfArmors++;	}		// -- Reset spec --	pstrcpy(gSaveSpec.name, "\p");		CalcCharacter();		return gReturnValue;}//*************************************************************************************//  Access functions//*************************************************************************************void AddCharHP (long hp){	gCharacter.currHP += hp;	if(gCharacter.currHP > gCharacter.maxHP)		gCharacter.currHP = gCharacter.maxHP;}void SubCharHP (long hp){	gCharacter.currHP -= hp;}long GetCharHP (void){	return gCharacter.currHP;}long GetCharMaxHP (void){	return gCharacter.maxHP;}Boolean IsCharDead (void){	if(gCharacter.currHP <= 0)		return true;	return false;}void SetBattleMenuPos (short x, short y){	gCharacter.battleMenuPos.h = x;	gCharacter.battleMenuPos.v = y;}short GetBattleMenuPosX (void){	return gCharacter.battleMenuPos.h;}short GetBattleMenuPosY (void){	return gCharacter.battleMenuPos.v;}Stats GetCharStats (void){	return gCharacter.stats;}short GetCharLv (void){	return gCharacter.lv;}void GetCharName (char name[256]){	CopyPascalStringToC(gCharacter.name, name);}void GetCharLv (char lv[256]){	Str255 lvStr = "\pLv: ";	Str255 numStr;	NumToString(gCharacter.lv, numStr);	pstrcat(lvStr, numStr);	CopyPascalStringToC(lvStr, lv);}void GetCharHP (char hp[256]){	Str255 hpStr = "\pHP: ";	Str255 numStr;	NumToString(gCharacter.currHP * 100 / gCharacter.maxHP, numStr);	pstrcat(hpStr, numStr);	pstrcat(hpStr, "\p%");	CopyPascalStringToC(hpStr, hp);}short GetCharStr (void){	return gCharacter.stats.str;}short GetCharSpd (void){	return gCharacter.stats.spd;}short GetCharMag (void){	return gCharacter.stats.mag;}long GetCharDamage (void){	return gCharacter.damage;}short GetCharHitPerc (void){	return gCharacter.hitPerc;}short GetCharElement (void){	return gCharacter.element;}void SetCharMapPosition (short plugID, short mapID, short x, short y){	gCharacter.plugID = plugID;	gCharacter.mapID = mapID;	gCharacter.mapPosition.h = x;	gCharacter.mapPosition.v = y;}void SetCharMapPosition (short x, short y){	gCharacter.mapPosition.h = x;	gCharacter.mapPosition.v = y;}Point GetCharMapPosition (void){	return gCharacter.mapPosition;}short GetCharPlugID (void){	return gCharacter.plugID;}void SetCharPlugID (short plugID){	gCharacter.plugID = plugID;}short GetSummonPlugID (void){	return gCharacter.summon.plugID;}short GetCharMapID (void){	return gCharacter.mapID;}short GetBattleOffsetX (void){	return gCharacter.holdPos.h;}short GetBattleOffsetY (void){	return gCharacter.holdPos.v;}short GetCharMapPositionX (void){	return gCharacter.mapPosition.h;}short GetCharMapPositionY (void){	return gCharacter.mapPosition.v;}void SetCharMapFacing (short mapFacing){	gCharacterInfo.mapFacing = mapFacing;}short GetCharMapFacing (void){	return gCharacterInfo.mapFacing;}void SetCharFlag (short flagNumber){	if(flagNumber <= kMaxFlags)		gCharacter.flag[flagNumber] = true;}Boolean GetCharFlag (short flagNumber){	if(flagNumber > kMaxFlags)		return true;	return gCharacter.flag[flagNumber];}Boolean RemoveCharItem (ItemRef item){	for(short i = 0; i < gCharacter.numOfItems; i++)		if(gCharacter.items[i].itemType == item.itemType && gCharacter.items[i].plugID == item.plugID && gCharacter.items[i].resID == item.resID)		{			gCharacter.numOfItems--;			gCharacter.items[i] = gCharacter.items[gCharacter.numOfItems];			CalcCharacter();			return true;		}	for(short i = 0; i < gCharacter.numOfArmors; i++)	{		if(gCharacter.armors[i].itemType == item.itemType && gCharacter.armors[i].plugID == item.plugID && gCharacter.armors[i].resID == item.resID)		{			gCharacter.numOfArmors--;			gCharacter.armors[i] = gCharacter.armors[gCharacter.numOfArmors];			CalcCharacter();			return true;		}	}	if(gCharacter.isWeapon == true)		if(gCharacter.weapon.itemType == item.itemType && gCharacter.weapon.plugID == item.plugID && gCharacter.weapon.resID == item.resID)		{			gCharacter.isWeapon = false;			CalcCharacter();			return true;		}	if(gCharacter.isSummon == true)		if(gCharacter.summon.itemType == item.itemType && gCharacter.summon.plugID == item.plugID && gCharacter.summon.resID == item.resID)		{			gCharacter.isSummon = false;			CalcCharacter();			return true;		}	return false;}void DrawMapCharacter (void){	switch(gCharacterInfo.mapFacing)	{		case kMapFacingNorth1:			SetRect(&gCharSpriteSrcRect, 32, 0, 64, 32);			DrawSprite(gCharacterInfo.mapSprite, &gCharSpriteSrcRect, &gCharMapDstRect);			break;		case kMapFacingNorth2:			SetRect(&gCharSpriteSrcRect, 32, 32, 64, 64);			DrawSprite(gCharacterInfo.mapSprite, &gCharSpriteSrcRect, &gCharMapDstRect);			break;		case kMapFacingWest1:			SetRect(&gCharSpriteSrcRect, 0, 0, 32, 32);			DrawSprite(gCharacterInfo.mapSprite, &gCharSpriteSrcRect, &gCharMapDstRect);			break;		case kMapFacingWest2:			SetRect(&gCharSpriteSrcRect, 0, 32, 32, 64);			DrawSprite(gCharacterInfo.mapSprite, &gCharSpriteSrcRect, &gCharMapDstRect);			break;		case kMapFacingSouth1:			SetRect(&gCharSpriteSrcRect, 96, 0, 128, 32);			DrawSprite(gCharacterInfo.mapSprite, &gCharSpriteSrcRect, &gCharMapDstRect);			break;		case kMapFacingSouth2:			SetRect(&gCharSpriteSrcRect, 96, 32, 128, 64);			DrawSprite(gCharacterInfo.mapSprite, &gCharSpriteSrcRect, &gCharMapDstRect);			break;		case kMapFacingEast1:			SetRect(&gCharSpriteSrcRect, 64, 0, 96, 32);			DrawSprite(gCharacterInfo.mapSprite, &gCharSpriteSrcRect, &gCharMapDstRect);			break;		case kMapFacingEast2:			SetRect(&gCharSpriteSrcRect, 64, 32, 96, 64);			DrawSprite(gCharacterInfo.mapSprite, &gCharSpriteSrcRect, &gCharMapDstRect);			break;	}}void DrawBattleCharacter (void){	Rect dstRect;	GetPortBounds(gCharacterInfo.battleSprite, &dstRect);	OffsetRect(&dstRect, 64, 288);	DrawLifeBar(gCharacter.currHP * 100 / gCharacter.maxHP);	DrawWeapon();	DrawSprite(gCharacterInfo.battleSprite, &dstRect);}void DrawBattleCharacterClear (void){	Rect dstRect;	GetPortBounds(gCharacterInfo.battleSprite, &dstRect);	OffsetRect(&dstRect, 64, 288);	DrawBattleBackground(&dstRect);	DrawLifeBar(gCharacter.currHP * 100 / gCharacter.maxHP);	DrawWeapon();	DrawSprite(gCharacterInfo.battleSprite, &dstRect);}void GetBattleInfo (Boolean * isWeapon, CGrafPtr * weapon, Point * offset, Boolean * isSummon, CGrafPtr * summon, SummonRef * summonData){	if(gCharacter.isWeapon == true)	{		BeginPlugUseResourceFile(gCharacter.weapon.plugID);		WeaponRef ** data = (WeaponRef **)GetResource(kWeaponResType, gCharacter.weapon.resID);		ErrorCheck(ResError(), "\pDACharacter:GetBattleInfo:BeginUseResourceFile");		error = GetSprite((**data).battleSprt, weapon);		ErrorCheck(ResError(), "\pDACharacter:GetBattleInfo:GetSprite");		SetPt(offset, gCharacter.holdPos.h - (**data).holdPos.v, gCharacter.holdPos.v - (**data).holdPos.h);		ReleaseResource((Handle)data);		EndPlugUseResourceFile();		*isWeapon = true;	}	else		*isWeapon = false;	if(gCharacter.isSummon == true)	{		BeginPlugUseResourceFile(gCharacter.summon.plugID);		SummonRef ** data = (SummonRef **)GetResource(kSummonResType, gCharacter.summon.resID);		ErrorCheck(ResError(), "\pDACharacter:GetBattleInfo:BeginUseResourceFile");		error = GetSprite((**data).battleSprt, summon);		ErrorCheck(ResError(), "\pDACharacter:GetBattleInfo:GetSprite");		*summonData = **data;		ReleaseResource((Handle)data);		EndPlugUseResourceFile();		*isSummon = true;	}	else		*isSummon = false;}void RunDamage (void){	if(Random(100) <= 50)	{		long damage = gCharacter.maxHP * Random(30) / 100;		gCharacter.currHP -= damage;		if(gCharacter.currHP <= 0)			gCharacter.currHP = 1;		Str255 runText = "\pYou suffered ";		Str255 numStr;		NumToString(damage, numStr);		pstrcat(runText, numStr);		pstrcat(runText, "\p points of damage.");		MapTalkAction(runText);	}}//*************************************************************************************//  Misc functions//*************************************************************************************void CharLvUp (void){	SetGWorld(OldWindow());	if(gCharacter.lv >= kMaxLevel)	{		MapTalkAction("\pI would level you up if you weren't on the max level.");		return;	}	long cost = (gCharacter.lv + 1) * 100;	Str31 costStr;	NumToString(cost, costStr);	Str255 string = "\pFor ";	pstrcat(string, costStr);	pstrcat(string, "\pg I'll give you the training required to progress to the next level.");	if(MapYesNoAction(string) == true)	{		if(gCharacter.gold < cost)			MapTalkAction("\pSorry you'll need more gold.");		else		{			PlayLevelUpSound();			gCharacter.gold -= cost;			gCharacter.lv++;			if(gCharacter.lv == 5)			{				if(pstrcmp(gCharacter.occupation, kOccupationSoldier) == 0)				{					gCharacter.armors[gCharacter.numOfArmors].itemType	= kItemLv5;					gCharacter.armors[gCharacter.numOfArmors].plugID	= 1;					gCharacter.armors[gCharacter.numOfArmors].resID		= 600;					gCharacter.numOfArmors++;				}				else if(pstrcmp(gCharacter.occupation, kOccupationFigher) == 0)				{					gCharacter.armors[gCharacter.numOfArmors].itemType	= kItemLv5;					gCharacter.armors[gCharacter.numOfArmors].plugID	= 1;					gCharacter.armors[gCharacter.numOfArmors].resID		= 601;					gCharacter.numOfArmors++;				}				else if(pstrcmp(gCharacter.occupation, kOccupationKnight) == 0)				{					gCharacter.armors[gCharacter.numOfArmors].itemType	= kItemLv5;					gCharacter.armors[gCharacter.numOfArmors].plugID	= 1;					gCharacter.armors[gCharacter.numOfArmors].resID		= 602;					gCharacter.numOfArmors++;				}				else if(pstrcmp(gCharacter.occupation, kOccupationThief) == 0)				{					gCharacter.armors[gCharacter.numOfArmors].itemType	= kItemLv5;					gCharacter.armors[gCharacter.numOfArmors].plugID	= 1;					gCharacter.armors[gCharacter.numOfArmors].resID		= 603;					gCharacter.numOfArmors++;				}				else if(pstrcmp(gCharacter.occupation, kOccupationMage) == 0)				{					gCharacter.armors[gCharacter.numOfArmors].itemType	= kItemLv5;					gCharacter.armors[gCharacter.numOfArmors].plugID	= 1;					gCharacter.armors[gCharacter.numOfArmors].resID		= 604;					gCharacter.numOfArmors++;				}				MapTalkAction("\pSpecial level 5 item received.");			}			else if(gCharacter.lv == 10)			{				if(pstrcmp(gCharacter.occupation, kOccupationSoldier) == 0)				{					gCharacter.armors[gCharacter.numOfArmors].itemType	= kItemLv10;					gCharacter.armors[gCharacter.numOfArmors].plugID	= 1;					gCharacter.armors[gCharacter.numOfArmors].resID		= 700;					gCharacter.numOfArmors++;				}				else if(pstrcmp(gCharacter.occupation, kOccupationFigher) == 0)				{					gCharacter.armors[gCharacter.numOfArmors].itemType	= kItemLv10;					gCharacter.armors[gCharacter.numOfArmors].plugID	= 1;					gCharacter.armors[gCharacter.numOfArmors].resID		= 701;					gCharacter.numOfArmors++;				}				else if(pstrcmp(gCharacter.occupation, kOccupationKnight) == 0)				{					gCharacter.armors[gCharacter.numOfArmors].itemType	= kItemLv10;					gCharacter.armors[gCharacter.numOfArmors].plugID	= 1;					gCharacter.armors[gCharacter.numOfArmors].resID		= 702;					gCharacter.numOfArmors++;				}				else if(pstrcmp(gCharacter.occupation, kOccupationThief) == 0)				{					gCharacter.armors[gCharacter.numOfArmors].itemType	= kItemLv10;					gCharacter.armors[gCharacter.numOfArmors].plugID	= 1;					gCharacter.armors[gCharacter.numOfArmors].resID		= 703;					gCharacter.numOfArmors++;				}				else if(pstrcmp(gCharacter.occupation, kOccupationMage) == 0)				{					gCharacter.armors[gCharacter.numOfArmors].itemType	= kItemLv10;					gCharacter.armors[gCharacter.numOfArmors].plugID	= 1;					gCharacter.armors[gCharacter.numOfArmors].resID		= 704;					gCh